// Author: abhinavkumarrath #include <bits/stdc++.h>using namespace std; #pragma GCC optimize("O3,unroll-loops")#pragma GCC target("avx2,bmi,bmi2,lzcnt,popcnt") using ll = long long;using vi = vector<int>;using vll = vector<ll>;using pii = pair<int, int>; #define pb push_back#define all(x) (x).begin(), (x).end()#define sz(x) (int)(x).size()#define fi first#define se second #define rep(i, a, b) for (int i = (a); i < (b); ++i)#define forn(i, n) rep(i, 0, n)#define per(i, a, b) for (int i = (b) - 1; i >= (a); --i)#define rofn(i, n) per(i, 0, n) template<class T> bool chmin(T& a, const T& b) { if (b < a) { a = b; return 1; } return 0; }template<class T> bool chmax(T& a, const T& b) { if (a < b) { a = b; return 1; } return 0; } void yes() { cout << "YES\n"; }void no() { cout << "NO\n"; } const int INF = 1e9;const ll LINF = 1e18; void solve() {    string s;    if (!(cin >> s)) return;    int n = sz(s);        if (n == 1) {        if (s[0] == '0' || s[0] == 'X' || s[0] == '_') cout << 1 << "\n";        else cout << 0 << "\n";        return;    }        int low = 1;    forn(i, n - 1) low *= 10;    int high = low * 10 - 1;        while (low % 25 != 0) low++;        int ans = 0;    for (int i = low; i <= high; i += 25) {        string t = to_string(i);        bool ok = true;        char x = '-';                forn(j, n) {            if (s[j] == '_') continue;            if (s[j] == 'X') {                if (x != '-' && x != t[j]) {                    ok = false;                    break;                }                x = t[j];            } else if (s[j] != t[j]) {                ok = false;                break;            }        }        if (ok) ans++;    }        cout << ans << "\n";} int main() {    ios_base::sync_with_stdio(false);    cin.tie(nullptr);        int t = 1;    //cin >> t;    while (t--) {        solve();    }    return 0;}